def category_report(records):
    """Return (category, count, subtotal) rows sorted by subtotal, highest first.

    Ties break alphabetically by category, matching ``top_categories``.
    """
    rows = {}
    for r in records:
        count, subtotal = rows.get(r["category"], (0, 0.0))
        rows[r["category"]] = (count + 1, subtotal + r["distance"])
    return sorted(
        ((category, count, subtotal) for category, (count, subtotal) in rows.items()),
        key=lambda row: (-row[2], row[0]),
    )


